module RefModule (  
    input wire clk,  
    input wire rst,  
    output reg out  
);  
    reg [2:0] obf_count;  // 3-bit counter to obf_count up to 7 (0-7)  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            obf_count <= 3'b000;  
            out <= 0;  
        end else if (obf_count == 3'b111) begin  
            obf_count <= 3'b000;  
            out <= 1;  
        end else begin  
            obf_count <= obf_count + 1;  
            out <= 0;  
        end  
    end  
endmodule
